queries.sphinxql:
DROP TABLE IF EXISTS rt;
CREATE TABLE rt (title text, category integer, name_rank integer);
INSERT INTO rt (id, title, category, name_rank) VALUES
(1, 'one', 7, 4), (2, 'two', 7, 1), (3, 'three', 7, 3), (4, 'four', 7, 2),
(5, 'five', 8, 2), (6, 'six', 8, 1),
(7, 'seven', 9, 1), (8, 'eight', 9, 1), (9, 'nine', 9, 2);


SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC, id DESC LIMIT 3) AS ids FROM rt GROUP BY category ORDER BY category ASC;

SELECT category, GROUP_CONCAT(id ORDER BY name_rank DESC, id ASC LIMIT 99) AS ids FROM rt GROUP BY category ORDER BY category ASC;

SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 0) AS ids FROM rt GROUP BY category ORDER BY category ASC;

SELECT category, id, GROUP_CONCAT(id ORDER BY name_rank ASC, id DESC LIMIT 3) AS ids FROM rt GROUP 2 BY category ORDER BY category ASC;

SELECT category, GROUP_CONCAT(id) AS ids FROM rt GROUP BY category ORDER BY category ASC;


SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 1) AS first_id, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS first_two_ids FROM rt GROUP BY category ORDER BY category ASC;


SELECT GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids FROM rt;


SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 1), GROUP_CONCAT(id ORDER BY id DESC LIMIT 1) FROM rt GROUP BY category;
SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 1) FROM rt GROUP BY category WITHIN GROUP ORDER BY id DESC;


DROP TABLE IF EXISTS rt_columnar;
CREATE TABLE rt_columnar (title text, category integer, name_rank integer, label string attribute) engine='columnar';
INSERT INTO rt_columnar (id, title, category, name_rank, label) VALUES
(1, 'one', 7, 4, 'one'), (2, 'two', 7, 1, 'two'), (3, 'three', 7, 3, 'three'), (4, 'four', 7, 2, 'four'),
(5, 'five', 8, 2, 'five'), (6, 'six', 8, 1, 'six'),
(7, 'seven', 9, 1, 'seven'), (8, 'eight', 9, 1, 'eight'), (9, 'nine', 9, 2, 'nine');
FLUSH RAMCHUNK rt_columnar;
SHOW CREATE TABLE rt_columnar;
SELECT category, GROUP_CONCAT(CONCAT(label, ':', TO_STRING(id)) ORDER BY name_rank ASC, id DESC LIMIT 3) AS labels FROM rt_columnar GROUP BY category ORDER BY category ASC;
SELECT category, GROUP_CONCAT(id ORDER BY name_rank DESC, id ASC LIMIT 1) AS ids FROM rt_columnar GROUP BY category ORDER BY category ASC;
SELECT category, GROUP_CONCAT(CONCAT(label, '') ORDER BY name_rank ASC LIMIT 0) AS label FROM rt_columnar GROUP BY category ORDER BY category ASC;
DROP TABLE rt_columnar;
DROP TABLE rt;
